    "slug": "proptech-residential-sales-crm",
    "title": "PropTech Residential Sales CRM — UK Estate Agency Group",
    "metaTitle": "PropTech Residential Sales CRM — UK Estate Agency Group — ClickMasters Case Study",
    "metaDesc": "A UK national estate agency group with 240 branches, 1,800 negotiators, and £4.2B annual residential sales nee...",
    "sector": "PropTech / Estate Agency",
