    "title": "MedTech AI Wound Assessment Platform — UK Community Nursing",
    "metaTitle": "MedTech AI Wound Assessment Platform — UK Community Nursing — ClickMasters Case Study",
    "metaDesc": "An NHS Community Trust providing district nursing to 84,000 patients wanted to build an AI-assisted wound asse...",
    "sector": "MedTech / Wound Care",
