    "title": "GovTech NHS 111 Digital Triage Enhancement — IUC Provider",
    "metaTitle": "GovTech NHS 111 Digital Triage Enhancement — IUC Provider — ClickMasters Case Study",
    "metaDesc": "An NHS Integrated Urgent Care (IUC) provider operating NHS 111 services for a population of 1.8 million people...",
    "sector": "GovTech / NHS 111",
    "country": "UK",
