    "title": "GovTech DEFRA Environmental Permit Management — UK Environment Agency",
    "metaTitle": "GovTech DEFRA Environmental Permit Management — UK Environment Agency — ClickMasters Case Study",
    "metaDesc": "An Environment Agency-contracted digital supplier building a digital environmental permit management system fo...",
    "sector": "GovTech / Environment",
    "country": "UK",
