    "slug": "fintech-crypto-asset-trading-platform",
    "title": "FinTech Crypto Asset Trading Platform — UK FCA Registered",
    "metaTitle": "FinTech Crypto Asset Trading Platform — UK FCA Registered — ClickMasters Case Study",
    "metaDesc": "A UK FCA-registered Cryptoasset Business (registered under the Money Laundering Regulations 2017 for cryptoass...",
    "sector": "FinTech / Crypto",
