    "title": "PropTech Residential Property Search Platform — UK National Portal",
    "metaTitle": "PropTech Residential Property Search Platform — UK National Portal — ClickMasters Case Study",
    "metaDesc": "A UK property search startup building a competing search platform to Rightmove and Zoopla needed to build a co...",
    "sector": "PropTech / Property Search",
