    "title": "FinTech Crypto Asset Platform — UK FCA Registered Business",
    "metaTitle": "FinTech Crypto Asset Platform — UK FCA Registered Business — ClickMasters Case Study",
    "metaDesc": "A UK company registered with the FCA as a cryptoasset business (under MLRs 2017 Schedule 7A) wanted to build a...",
    "sector": "FinTech / CryptoAsset",
    "country": "UK",
    "status": "On Time",
