    "title": "PropTech Rent Collection SaaS — UK Build-to-Rent Operator",
    "metaTitle": "PropTech Rent Collection SaaS — UK Build-to-Rent Operator — ClickMasters Case Study",
    "metaDesc": "A UK Build-to-Rent (BTR) operator managing 3,200 rental apartments across 8 developments needed to replace man...",
    "sector": "PropTech / Build-to-Rent",
    "country": "UK",
    "status": "On Time",
