    "title": "EdTech Vocational Training Platform — UK Apprenticeship Provider",
    "metaTitle": "EdTech Vocational Training Platform — UK Apprenticeship Provider — ClickMasters Case Study",
    "metaDesc": "A UK apprenticeship training provider delivering Level 2–5 apprenticeships to 2,400 apprentices across 180 emp...",
    "sector": "EdTech / FE",
