    "title": "FinTech Debt Management Platform — UK FCA Authorised Debt Counsellor",
    "metaTitle": "FinTech Debt Management Platform — UK FCA Authorised Debt Counsellor — ClickMasters Case Study",
    "metaDesc": "A UK FCA-authorised Debt Management Plan (DMP) provider administering 4,800 active DMPs needed to replace thei...",
    "sector": "FinTech / Debt Management",
    "country": "UK",
    "status": "On Time",
