    "slug": "healthtech-diabetes-management-app-nhs",
    "title": "HealthTech Diabetes Management App — NHS Pilot, DTAC Approved",
    "metaTitle": "HealthTech Diabetes Management App — NHS Pilot, DTAC Approved — ClickMasters Case Study",
    "metaDesc": "A UK digital health charity wanted to build a consumer-facing diabetes self-management app, seeking NHS App Li...",
    "sector": "HealthTech / Consumer Health",
    "country": "UK",
    "status": "On Time",
