    "title": "LegalTech Court Listing Management — HM Courts &amp; Tribunals Service Digital",
    "metaTitle": "LegalTech Court Listing Management — HM Courts &amp; Tribunals Service Digital — ClickMasters Case Study",
    "metaDesc": "An HMCTS-contracted specialist digital supplier building a court listing management pilot for a UK Crown Court...",
    "sector": "LegalTech / GovTech",
    "country": "UK",
